export const Animations = () => {
  const [showError, setShowError] = useState(false);

  return (
    <Stack gap={6}>
      <Box>
        <Text fontWeight="bold" mb={2}>
          Focus Animation
        </Text>
        <Text fontSize="sm" color="gray.600" mb={3}>
          Click on the input to see the glow effect
        </Text>
        <Input
          label="Focus me"
          placeholder="Click to see focus animation"
          helperText="Input shows a subtle glow effect on focus"
        />
      </Box>

      <Box>
        <Text fontWeight="bold" mb={2}>
          Hover Animation
        </Text>
        <Text fontSize="sm" color="gray.600" mb={3}>
          Hover over the input to see border color change
        </Text>
        <Input label="Hover me" placeholder="Hover to see border animation" />
      </Box>

      <Box>
        <Text fontWeight="bold" mb={2}>
          Error Shake Animation
        </Text>
        <Text fontSize="sm" color="gray.600" mb={3}>
          Toggle error state to see shake animation
        </Text>
        <Stack gap={3}>
          <Input
            label="Email"
            placeholder="Enter email"
            invalid={showError}
            errorText={showError ? "Please enter a valid email address" : undefined}
          />
          <Button onClick={() => setShowError(!showError)} size="sm" width="fit-content">
            {showError ? "Clear Error" : "Show Error"}
          </Button>
        </Stack>
      </Box>

      <Box>
        <Text fontWeight="bold" mb={2}>
          Disabled State
        </Text>
        <Input label="Disabled input" placeholder="This input is disabled" disabled />
      </Box>
    </Stack>
  );
};

export const WithoutAnimations = () => (
  <Stack gap={4}>
    <Text fontSize="sm" color="gray.600">
      Set animated=false to disable all animations
    </Text>
    <Input
      label="No animations"
      placeholder="Animations disabled"
      helperText="This input has animations disabled"
      animated={false}
    />
  </Stack>
);

export const InteractiveForm = () => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [submitted, setSubmitted] = useState(false);

  const emailInvalid = submitted && !email.includes("@");
  const passwordInvalid = submitted && password.length < 8;

  const handleSubmit = () => {
    setSubmitted(true);
  };

  return (
    <Stack gap={4} maxW="400px">
      <Input
        label="Email"
        placeholder="Enter your email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
        invalid={emailInvalid}
        errorText={emailInvalid ? "Please enter a valid email" : undefined}
      />
      <Input
        label="Password"
        type="password"
        placeholder="Enter your password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
        invalid={passwordInvalid}
        errorText={passwordInvalid ? "Password must be at least 8 characters" : undefined}
        helperText={!passwordInvalid ? "Must be at least 8 characters" : undefined}
      />
      <Button onClick={handleSubmit}>Submit</Button>
      {submitted && !emailInvalid && !passwordInvalid && (
        <Text color="green.500">Form submitted successfully!</Text>
      )}
    </Stack>
  );
};
